import{_ as n,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Kontextoptimierung: Token-sparende Sitzungsausführung | Agent App Factory Tutorial","description":"Lernen Sie, wie Sie mit dem Befehl factory continue Token sparen, indem Sie in jeder Phase eine neue Sitzung starten. Durch die sitzungsbasierte Ausführung erhält jede Phase einen sauberen Kontext, was die Nutzungskosten erheblich senkt. Dieses Tutorial behandelt Kontextisolierungsstrategien, Statuswiederherstellungsmechanismen und Best Practices, um Ihnen zu helfen, Token-Optimierungstechniken zu beherrschen.","frontmatter":{"title":"Kontextoptimierung: Token-sparende Sitzungsausführung | Agent App Factory Tutorial","sidebarTitle":"Kontextoptimierung","subtitle":"Kontextoptimierung: Sitzungsbasierte Ausführung","description":"Lernen Sie, wie Sie mit dem Befehl factory continue Token sparen, indem Sie in jeder Phase eine neue Sitzung starten. Durch die sitzungsbasierte Ausführung erhält jede Phase einen sauberen Kontext, was die Nutzungskosten erheblich senkt. Dieses Tutorial behandelt Kontextisolierungsstrategien, Statuswiederherstellungsmechanismen und Best Practices, um Ihnen zu helfen, Token-Optimierungstechniken zu beherrschen.","tags":["Fortgeschritten","Leistungsoptimierung","Token-Einsparung"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":160},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/advanced/context-optimization/index.md","filePath":"de/hyz1992/agent-app-factory/advanced/context-optimization/index.md"}'),a={name:"de/hyz1992/agent-app-factory/advanced/context-optimization/index.md"};function r(o,e,l,u,d,h){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="kontextoptimierung-sitzungsbasierte-ausfuhrung" tabindex="-1">Kontextoptimierung: Sitzungsbasierte Ausführung <a class="header-anchor" href="#kontextoptimierung-sitzungsbasierte-ausfuhrung" aria-label="Permalink to &quot;Kontextoptimierung: Sitzungsbasierte Ausführung&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Den Befehl <code>factory continue</code> verwenden, um die Pipeline in einer neuen Sitzung fortzusetzen</li><li>Die Vorteile verstehen, die jede Phase mit einem sauberen, exklusiven Kontext bietet</li><li>Methoden zur erheblichen Reduzierung des Token-Verbrauchs beherrschen</li><li>Unterbrechungswiederherstellung unterstützen – jederzeit pausieren und fortsetzen</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>Wenn Sie eine vollständige 7-Phasen-Pipeline in einem KI-Assistenten (wie Claude Code) ausführen, können folgende Probleme auftreten:</p><ul><li><strong>Immer mehr Token</strong>: Mit der fortschreitenden Konversation wird der Kontext länger, und jede Phase muss den Inhalt aller vorherigen Phasen laden</li><li><strong>Steigende Kosten</strong>: Lange Konversationen bedeuten mehr Eingabe-Tokens, und die Kosten steigen rapide an</li><li><strong>Langsamere Antworten</strong>: Ein zu langer Kontext kann zu längeren Antwortzeiten führen</li><li><strong>Schwierige Wiederherstellung</strong>: Wenn eine Phase fehlschlägt, erfordert ein Neustart das erneute Laden großer Mengen an Kontext</li></ul><div class="tip custom-block"><p class="custom-block-title">Kernproblem</p><p>Die Kontextakkumulation bei langen Konversationen ist eine inhärente Eigenschaft von KI-Assistenten, aber wir können dieses Problem durch &quot;sitzungsbasierte Ausführung&quot; umgehen.</p></div><h2 id="wann-sie-diese-technik-verwenden-sollten" tabindex="-1">Wann Sie diese Technik verwenden sollten <a class="header-anchor" href="#wann-sie-diese-technik-verwenden-sollten" aria-label="Permalink to &quot;Wann Sie diese Technik verwenden sollten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Sitzungsbasierte Ausführung verwenden?</th><th>Grund</th></tr></thead><tbody><tr><td>Vollständige Ausführung der 7-Phasen-Pipeline</td><td>✅ Stark empfohlen</td><td>Jedes Token ist wertvoll</td></tr><tr><td>Nur 1-2 Phasen ausführen</td><td>⚠️ Optional</td><td>Kontext ist kurz, nicht unbedingt erforderlich</td></tr><tr><td>Eine Phase debuggen</td><td>⚠️ Optional</td><td>Häufige Wiederholungen können die Kosten für Sitzungswechsel erhöhen</td></tr><tr><td>Nach langer Unterbrechung fortsetzen</td><td>✅ Muss verwendet werden</td><td>Vermeidung des Ladens veralteter Kontexte</td></tr></tbody></table><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Agent App Factory unterstützt <strong>sitzungsbasierte Ausführung</strong>. Die Kernidee ist:</p><p><strong>Nach Abschluss jeder Phase wird die nächste Phase in einer neuen Sitzung ausgeführt.</strong></p><p>Die Vorteile davon:</p><ol><li><strong>Sauberer Kontext</strong>: Jede Phase lädt nur die notwendigen Eingabedateien, ohne auf den Konversationsverlauf angewiesen zu sein</li><li><strong>Token-Einsparung</strong>: Vermeidet die wiederholte Übergabe aller Inhalte vorheriger Phasen an die KI</li><li><strong>Wiederherstellbarkeit</strong>: Jederzeit unterbrechen und später in einer neuen Sitzung fortsetzen, ohne Fortschritt zu verlieren</li><li><strong>Plattformübergreifende Kompatibilität</strong>: Geeignet für alle KI-Assistenten (Claude Code, OpenCode, Cursor usw.)</li></ol><h3 id="kontextisolierungsstrategie" tabindex="-1">Kontextisolierungsstrategie <a class="header-anchor" href="#kontextisolierungsstrategie" aria-label="Permalink to &quot;Kontextisolierungsstrategie&quot;">​</a></h3><p>Um sitzungsbasierte Ausführung zu ermöglichen, verwendet Agent App Factory eine <strong>Kontextisolierungsstrategie</strong>:</p><div class="info custom-block"><p class="custom-block-title">Was ist Kontextisolierung?</p><p>Kontextisolierung bedeutet, dass jeder Agent nur auf Dateieingaben angewiesen ist, nicht auf den Konversationsverlauf. Egal was zuvor passiert ist, der Agent liest Informationen nur aus den angegebenen Eingabedateien.</p></div><p>Bei der Ausführung jedes Agents:</p><ul><li>✅ <strong>Nur lesen</strong> der in <code>pipeline.yaml</code> definierten <code>inputs</code>-Dateien</li><li>❌ <strong>Nicht verwenden</strong> irgendwelcher &quot;Erinnerungen&quot; aus dem Konversationsverlauf</li><li>❌ <strong>Nicht annehmen</strong>, dass er weiß, was in vorherigen Phasen passiert ist</li></ul><p>Zum Beispiel beim Ausführen des Tech Agents:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">A[Tech Agent] --&gt; B[liest artifacts/prd/prd.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">B --&gt; C[generiert artifacts/tech/tech.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">C --&gt; D[aktualisiert .factory/state.json]</span></span></code></pre></div><p>Der Tech Agent kümmert sich nur um <code>artifacts/prd/prd.md</code> und denkt nicht darüber nach, &quot;was der Benutzer zuvor gesagt hat, was für eine App er erstellen möchte&quot;. Alle Informationen kommen aus den Eingabedateien.</p><h3 id="statuswiederherstellungsmechanismus" tabindex="-1">Statuswiederherstellungsmechanismus <a class="header-anchor" href="#statuswiederherstellungsmechanismus" aria-label="Permalink to &quot;Statuswiederherstellungsmechanismus&quot;">​</a></h3><p>Wenn Sie <code>factory continue</code> ausführen, wird das System:</p><ol><li><code>.factory/state.json</code> lesen, um den aktuellen Fortschritt zu erhalten</li><li><code>.factory/pipeline.yaml</code> lesen, um die nächste Phase zu bestimmen</li><li><strong>Nur die für diese Phase erforderlichen Eingabedateien laden</strong></li><li>Ein neues KI-Assistenten-Fenster starten, um die Ausführung fortzusetzen</li></ol><p>Die Statusdatei (<code>.factory/state.json</code>) ist das &quot;Gedächtniszentrum&quot; des gesamten Systems:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tech&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T12:00:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Nach Abschluss jeder Phase wird der Status in dieser Datei aktualisiert. Wenn eine neue Sitzung startet, muss nur diese Datei gelesen werden, um zu wissen, wo wir gerade sind.</p><h2 id="🎒-vorbereitung-vor-dem-start" tabindex="-1">🎒 Vorbereitung vor dem Start <a class="header-anchor" href="#🎒-vorbereitung-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitung vor dem Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Voraussetzungsprüfung</p><p>Bevor Sie mit diesem Tutorial beginnen, stellen Sie sicher, dass:</p><ul><li>[ ] Sie <a href="./../../start/getting-started/">Schnellstart</a> abgeschlossen haben und ein Factory-Projekt initialisiert haben</li><li>[ ] Sie die <a href="./../../start/pipeline-overview/">Übersicht über die 7-Phasen-Pipeline</a> kennen</li><li>[ ] Claude Code (oder einen anderen KI-Assistenten) installiert haben</li></ul><p>Falls noch nicht erledigt, schließen Sie bitte zuerst diese Voraussetzungen ab.</p></div><h2 id="schritt-fur-schritt" tabindex="-1">Schritt für Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt für Schritt&quot;">​</a></h2><p>Lassen Sie uns anhand eines praktischen Szenarios lernen, wie Sie den Befehl <code>factory continue</code> verwenden.</p><h3 id="szenario" tabindex="-1">Szenario <a class="header-anchor" href="#szenario" aria-label="Permalink to &quot;Szenario&quot;">​</a></h3><p>Angenommen, Sie führen eine 7-Phasen-Pipeline aus und haben bereits die Phasen <code>bootstrap</code> und <code>prd</code> abgeschlossen. Sie befinden sich in der Phase <code>ui</code> und warten auf Bestätigung.</p><h3 id="schritt-1-in-neuer-sitzung-fortsetzen-am-checkpoint-auswahlen" tabindex="-1">Schritt 1: &quot;In neuer Sitzung fortsetzen&quot; am Checkpoint auswählen <a class="header-anchor" href="#schritt-1-in-neuer-sitzung-fortsetzen-am-checkpoint-auswahlen" aria-label="Permalink to &quot;Schritt 1: &quot;In neuer Sitzung fortsetzen&quot; am Checkpoint auswählen&quot;">​</a></h3><p>Wenn eine Phase abgeschlossen ist, zeigt der Sisyphus-Scheduler eine Optionstabelle an:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ ui abgeschlossen!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Generierte Artefakte:</span></span>
<span class="line"><span>- artifacts/ui/ui.schema.yaml</span></span>
<span class="line"><span>- artifacts/ui/preview.web/index.html</span></span>
<span class="line"><span>- artifacts/ui/preview.web/styles.css</span></span>
<span class="line"><span>- artifacts/ui/preview.web/app.js</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 📋 Bitte wählen Sie die nächste Aktion                      │</span></span>
<span class="line"><span>│ Geben Sie eine Optionsnummer (1-5) ein und drücken Sie Enter│</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Option │ Beschreibung                                       │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 1    │ Nächste Phase fortsetzen (gleiche Sitzung)           │</span></span>
<span class="line"><span>│      │ Ich werde die tech-Phase fortsetzen                  │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 2    │ In neuer Sitzung fortsetzen ⭐ Empfohlene Option, spart Token │</span></span>
<span class="line"><span>│      │ Führen Sie in einem neuen Terminal-Fenster aus: factory continue │</span></span>
<span class="line"><span>│      │ (Startet automatisch ein neues Claude Code-Fenster und setzt die Pipeline fort) │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 3    │ Diese Phase wiederholen                              │</span></span>
<span class="line"><span>│      │ ui-Phase erneut ausführen                            │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 4    │ Nach Änderung der Artefakte erneut ausführen         │</span></span>
<span class="line"><span>│      │ Ändern Sie artifacts/prd/prd.md und führen Sie erneut aus │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 5    │ Pipeline pausieren                                   │</span></span>
<span class="line"><span>│      │ Aktuellen Fortschritt speichern, später fortsetzen   │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💡 Tipp: Geben Sie eine Zahl zwischen 1-5 ein und drücken Sie Enter zur Bestätigung</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><ul><li>Option 2 ist mit &quot;⭐ Empfohlene Option, spart Token&quot; markiert</li></ul><p>In der aktuellen Sitzung können wir Option 5 (Pipeline pausieren) wählen und dann in einem neuen Terminal-Fenster <code>factory continue</code> ausführen.</p><p><strong>Warum</strong></p><ul><li>Option 1 ist &quot;Nächste Phase fortsetzen (gleiche Sitzung)&quot;, was in der aktuellen Sitzung fortsetzt und den Kontext akkumuliert</li><li>Option 2 ist &quot;In neuer Sitzung fortsetzen&quot;, was die nächste Phase mit einem neuen, sauberen Kontext ausführt, <strong>spart Token</strong></li><li>Option 5 ist &quot;Pipeline pausieren&quot;, was den aktuellen Fortschritt speichert, den Sie später mit <code>factory continue</code> wiederherstellen können</li></ul><h3 id="schritt-2-factory-continue-in-einem-neuen-terminal-fenster-ausfuhren" tabindex="-1">Schritt 2: <code>factory continue</code> in einem neuen Terminal-Fenster ausführen <a class="header-anchor" href="#schritt-2-factory-continue-in-einem-neuen-terminal-fenster-ausfuhren" aria-label="Permalink to &quot;Schritt 2: \`factory continue\` in einem neuen Terminal-Fenster ausführen&quot;">​</a></h3><p>Öffnen Sie ein neues Terminal-Fenster (oder einen neuen Tab), wechseln Sie in Ihr Projektverzeichnis und führen Sie aus:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent Factory - Continue in New Session</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pipeline Status:</span></span>
<span class="line"><span>────────────────────────────────────────</span></span>
<span class="line"><span>Projekt: my-awesome-app</span></span>
<span class="line"><span>Status: Wartend</span></span>
<span class="line"><span>Aktuelle Phase: tech</span></span>
<span class="line"><span>Abgeschlossen: bootstrap, prd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starte neue Claude Code Sitzung...</span></span>
<span class="line"><span>✓ Neues Claude Code Fenster gestartet</span></span>
<span class="line"><span>(Bitte warten Sie, bis das Fenster geöffnet wird)</span></span></code></pre></div><p><strong>Was passiert ist</strong>:</p><ol><li>Der Befehl <code>factory continue</code> liest <code>.factory/state.json</code> und kennt den aktuellen Status</li><li>Zeigt die Statusinformationen des aktuellen Projekts an</li><li>Startet automatisch ein neues Claude Code Fenster und übergibt den Befehl &quot;Bitte setzen Sie die Pipeline fort&quot;</li><li>Das neue Fenster setzt automatisch ab der Phase <code>tech</code> fort</li></ol><h3 id="schritt-3-in-der-neuen-sitzung-fortsetzen" tabindex="-1">Schritt 3: In der neuen Sitzung fortsetzen <a class="header-anchor" href="#schritt-3-in-der-neuen-sitzung-fortsetzen" aria-label="Permalink to &quot;Schritt 3: In der neuen Sitzung fortsetzen&quot;">​</a></h3><p>Nachdem das neue Claude Code Fenster gestartet ist, sehen Sie eine neue Konversation, aber der Status wird vom zuvor gespeicherten Checkpoint wiederhergestellt.</p><p>In der neuen Sitzung wird der Agent:</p><ol><li><code>.factory/state.json</code> lesen, um die aktuelle Phase zu erhalten</li><li><code>.factory/pipeline.yaml</code> lesen, um die Eingaben und Ausgaben dieser Phase zu bestimmen</li><li><strong>Nur die für diese Phase erforderlichen Eingabedateien laden</strong> (z.B. <code>artifacts/prd/prd.md</code>)</li><li>Die Aufgaben dieser Phase ausführen</li></ol><p><strong>Wichtige Punkte</strong>:</p><ul><li>In der neuen Sitzung gibt es keinen Konversationsverlauf vorheriger Phasen</li><li>Der Agent liest Informationen nur aus Eingabedateien, nicht aus &quot;Erinnerungen&quot;</li><li>Das ist die Umsetzung der <strong>Kontextisolierung</strong></li></ul><h3 id="schritt-4-kontextisolierung-uberprufen" tabindex="-1">Schritt 4: Kontextisolierung überprüfen <a class="header-anchor" href="#schritt-4-kontextisolierung-uberprufen" aria-label="Permalink to &quot;Schritt 4: Kontextisolierung überprüfen&quot;">​</a></h3><p>Um zu überprüfen, ob die Kontextisolierung funktioniert, können Sie den Agent in der neuen Sitzung fragen:</p><p>&quot;Wissen Sie, was in der Bootstrap-Phase gemacht wurde?&quot;</p><p>Wenn die Kontextisolierung funktioniert, wird der Agent etwa so antworten:</p><p>&quot;Ich muss zuerst die relevanten Dateien überprüfen, um die vorherige Arbeit zu verstehen. Lassen Sie mich lesen...&quot;</p><p>Dann wird er versuchen, <code>input/idea.md</code> oder andere Dateien zu lesen, um Informationen zu erhalten, anstatt sie direkt aus dem Konversationsverlauf &quot;abzurufen&quot;.</p><p><strong>Checkpoint ✅</strong></p><ul><li>Neue Sitzung erfolgreich gestartet</li><li>Zeigt den korrekten Projektstatus an</li><li>Der Agent ist nur auf Eingabedateien angewiesen, nicht auf den Konversationsverlauf</li></ul><h3 id="schritt-5-die-verbleibenden-phasen-fortsetzen" tabindex="-1">Schritt 5: Die verbleibenden Phasen fortsetzen <a class="header-anchor" href="#schritt-5-die-verbleibenden-phasen-fortsetzen" aria-label="Permalink to &quot;Schritt 5: Die verbleibenden Phasen fortsetzen&quot;">​</a></h3><p>Nach Abschluss jeder Phase können Sie wählen:</p><ul><li>In der aktuellen Sitzung fortsetzen (Option 1) – geeignet für kurze Workflows</li><li><strong>In neuer Sitzung fortsetzen (Option 2)</strong> – <strong>Empfohlen, spart Token</strong></li><li>Pipeline pausieren (Option 5) – Später <code>factory continue</code> ausführen</li></ul><p>Für eine vollständige 7-Phasen-Pipeline wird empfohlen, für jede Phase &quot;In neuer Sitzung fortsetzen&quot; zu verwenden:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootstrap (Sitzung 1) → prd (Sitzung 2) → ui (Sitzung 3) → tech (Sitzung 4)</span></span>
<span class="line"><span>→ code (Sitzung 5) → validation (Sitzung 6) → preview (Sitzung 7)</span></span></code></pre></div><p>Jede Sitzung ist sauber und muss nicht den Inhalt aller vorherigen Phasen laden.</p><h2 id="fallstricke" tabindex="-1">Fallstricke <a class="header-anchor" href="#fallstricke" aria-label="Permalink to &quot;Fallstricke&quot;">​</a></h2><h3 id="fallstrick-1-vergessen-factory-continue-auszufuhren" tabindex="-1">Fallstrick 1: Vergessen, <code>factory continue</code> auszuführen <a class="header-anchor" href="#fallstrick-1-vergessen-factory-continue-auszufuhren" aria-label="Permalink to &quot;Fallstrick 1: Vergessen, \`factory continue\` auszuführen&quot;">​</a></h3><p><strong>Falsche Vorgehensweise</strong>:</p><ul><li>Direkt in der alten Sitzung mit der nächsten Phase beginnen</li><li>Oder Claude Code in einem neuen Fenster öffnen, ohne <code>factory continue</code> auszuführen</li></ul><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li>Verwenden Sie immer den Befehl <code>factory continue</code>, um eine neue Sitzung zu starten</li><li>Dieser Befehl liest automatisch den Status und übergibt die korrekten Anweisungen</li></ul><h3 id="fallstrick-2-historische-dateien-in-der-neuen-sitzung-wiederholt-laden" tabindex="-1">Fallstrick 2: Historische Dateien in der neuen Sitzung wiederholt laden <a class="header-anchor" href="#fallstrick-2-historische-dateien-in-der-neuen-sitzung-wiederholt-laden" aria-label="Permalink to &quot;Fallstrick 2: Historische Dateien in der neuen Sitzung wiederholt laden&quot;">​</a></h3><p><strong>Falsche Vorgehensweise</strong>:</p><ul><li>In der neuen Sitzung manuell verlangen, dass die KI Artefakte vorheriger Phasen liest</li><li>Denken, dass die KI &quot;wissen&quot; sollte, was zuvor passiert ist</li></ul><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li>Vertrauen Sie dem Kontextisolierungsmechanismus, der Agent liest automatisch Informationen aus den Eingabedateien</li><li>Stellen Sie nur die für diese Phase benötigten Eingabedateien bereit</li></ul><h3 id="fallstrick-3-factory-continue-projektubergreifend-verwenden" tabindex="-1">Fallstrick 3: <code>factory continue</code> projektübergreifend verwenden <a class="header-anchor" href="#fallstrick-3-factory-continue-projektubergreifend-verwenden" aria-label="Permalink to &quot;Fallstrick 3: \`factory continue\` projektübergreifend verwenden&quot;">​</a></h3><p><strong>Falsche Vorgehensweise</strong>:</p><ul><li><code>factory continue</code> in Projekt A ausführen, aber sich im Verzeichnis von Projekt B befinden</li></ul><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li><code>factory continue</code> prüft, ob das aktuelle Verzeichnis ein Factory-Projekt ist</li><li>Falls nicht, wird angezeigt, dass zuerst <code>factory init</code> ausgeführt werden muss</li></ul><h3 id="fallstrick-4-nach-anderung-von-artefakten-factory-continue-nicht-verwenden" tabindex="-1">Fallstrick 4: Nach Änderung von Artefakten <code>factory continue</code> nicht verwenden <a class="header-anchor" href="#fallstrick-4-nach-anderung-von-artefakten-factory-continue-nicht-verwenden" aria-label="Permalink to &quot;Fallstrick 4: Nach Änderung von Artefakten \`factory continue\` nicht verwenden&quot;">​</a></h3><p><strong>Szenario</strong>:</p><ul><li>Sie haben nach Abschluss einer Phase manuell Artefakte geändert (z.B. die PRD geändert)</li><li>Möchten mit der nächsten Phase fortfahren</li></ul><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li>Führen Sie <code>factory run</code> aus (startet ab der angegebenen Phase neu)</li><li>Oder führen Sie <code>factory continue</code> aus (setzt am aktuellen Checkpoint fort)</li><li>Setzen Sie nicht direkt in der alten Sitzung fort, da der Kontext möglicherweise inkonsistent ist</li></ul><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>In dieser Lektion haben wir gelernt, wie man den Befehl <code>factory continue</code> für sitzungsbasierte Ausführung verwendet:</p><h3 id="kernpunkte" tabindex="-1">Kernpunkte <a class="header-anchor" href="#kernpunkte" aria-label="Permalink to &quot;Kernpunkte&quot;">​</a></h3><ol><li><strong>Sitzungsbasierte Ausführung</strong>: Nach Abschluss jeder Phase wird die nächste Phase in einer neuen Sitzung ausgeführt</li><li><strong>Kontextisolierung</strong>: Der Agent ist nur auf Eingabedateien angewiesen, nicht auf den Konversationsverlauf</li><li><strong>Statuswiederherstellung</strong>: <code>.factory/state.json</code> zeichnet den aktuellen Fortschritt auf, neue Sitzungen können wiederherstellen</li><li><strong>Token-Einsparung</strong>: Vermeidet das Laden zu langer Kontexte, senkt die Kosten erheblich</li></ol><h3 id="befehlsubersicht" tabindex="-1">Befehlsübersicht <a class="header-anchor" href="#befehlsubersicht" aria-label="Permalink to &quot;Befehlsübersicht&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Befehl</th><th>Funktion</th><th>Anwendungsszenario</th></tr></thead><tbody><tr><td><code>factory continue</code></td><td>Pipeline in neuer Sitzung fortsetzen</td><td>Nach Abschluss jeder Phase</td></tr><tr><td><code>factory run</code></td><td>Pipeline in aktueller Sitzung ausführen</td><td>Erstausführung oder Debugging</td></tr><tr><td><code>factory status</code></td><td>Aktuellen Projektstatus anzeigen</td><td>Fortschritt verstehen</td></tr></tbody></table><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><ul><li>✅ Bei vollständiger Ausführung der 7-Phasen-Pipeline verwenden Sie für jede Phase <code>factory continue</code></li><li>✅ Wählen Sie am Checkpoint &quot;In neuer Sitzung fortsetzen&quot; (Option 2)</li><li>✅ Vertrauen Sie dem Kontextisolierungsmechanismus, laden Sie keine historischen Dateien manuell</li><li>✅ Verwenden Sie <code>factory status</code>, um den Projektfortschritt zu überprüfen</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../security-permissions/">Berechtigungen und Sicherheitsmechanismen</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie die Capability Boundary Matrix verhindert, dass Agents ihre Befugnisse überschreiten</li><li>Überschreitungsbehandlungsmechanismen und Isolierung nicht vertrauenswürdiger Artefakte</li><li>Sicherheitscheckpoints und Berechtigungsprüfungsabläufe</li><li>Wie Sie die Berechtigungsdatei von Claude Code konfigurieren</li></ul></blockquote><p>Diese Lektion hilft Ihnen, die Sicherheitsmechanismen von Agent App Factory zu verstehen und sicherzustellen, dass jeder Agent nur in autorisierten Verzeichnissen Dateien liest und schreibt.</p><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>factory continue Befehl</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-144</td></tr><tr><td>Scheduler-Kontextoptimierung</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>113-154</td></tr><tr><td>Kontextisolierungsstrategie</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>1-64</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>launchClaudeCode(projectDir, nextStage, completedStages)</code>: Startet ein neues Claude Code Fenster</li><li><code>commandExists(cmd)</code>: Prüft, ob ein Befehl verfügbar ist</li><li><code>module.exports(projectDir)</code>: Hauptfunktion des Befehls <code>factory continue</code></li></ul><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>state.json</code>: Pfad zur Statusdatei (<code>.factory/state.json</code>)</li><li><code>pipeline.yaml</code>: Pfad zur Pipeline-Definitionsdatei (<code>.factory/pipeline.yaml</code>)</li><li><code>config.yaml</code>: Pfad zur Projektkonfigurationsdatei (<code>.factory/config.yaml</code>)</li></ul><p><strong>Wichtige Geschäftsregeln</strong>:</p><ul><li>BR-6-1: Jede Phase hat einen exklusiven, sauberen Kontext</li><li>BR-6-2: Verwendung des Befehls <code>factory continue</code> zum Fortsetzen</li><li>BR-6-3: Nur Dateien laden, die für die aktuelle Phase benötigt werden</li></ul></details>`,104)])])}const g=n(a,[["render",r]]);export{p as __pageData,g as default};
